<script setup lang="ts">
import{computed,nextTick,ref}from'vue';import{onLoad}from'@dcloudio/uni-app';import{medicalApi,type ClinicalNotebook}from'../../api/medical'
const notebook=ref<ClinicalNotebook|null>(null),loading=ref(true),section=ref('record'),examAnchor=ref(''),registerId=ref(0)
const diseases=computed(()=>(notebook.value?.diagnosis?.diseases||[]).map(item=>item.diseaseName).filter(Boolean).join('、')||'暂无确诊疾病')
function text(value?:unknown,fallback='暂无记录'){if(value===null||value===undefined||String(value).trim()==='')return fallback;return String(value)}
function formatTime(value?:string){return value?value.replace('T',' ').slice(0,16):'—'}
function back(){uni.navigateBack({fail:()=>uni.reLaunch({url:'/pages/records/index'})})}
async function load(){loading.value=true;try{notebook.value=await medicalApi.visitNotebook(registerId.value);if(!notebook.value.archived&&notebook.value.message)uni.showToast({title:notebook.value.message,icon:'none'})}finally{loading.value=false}}
onLoad(async options=>{registerId.value=Number(options?.registerId||0);section.value=String(options?.section||'record');if(!registerId.value){uni.showToast({title:'缺少就诊记录编号',icon:'none'});return}await load();if(section.value==='check')nextTick(()=>examAnchor.value='exam-section')})
</script>
<template><view class="detail-page"><view class="header"><view class="back" @tap="back">‹</view><view class="header-title"><text>门诊病历本</text><text>熙康云医院 · 患者查阅版</text></view><view class="medical-mark">+</view></view><scroll-view class="content" scroll-y :scroll-into-view="examAnchor"><view v-if="loading" class="state">正在读取病历…</view><template v-else-if="notebook"><view class="patient-card"><view class="patient-top"><view class="avatar">{{(notebook.header.realName||'患').slice(0,1)}}</view><view><text>{{notebook.header.realName||'患者'}}</text><text>{{notebook.header.gender||'—'}} · {{notebook.header.age!=null?`${notebook.header.age}岁`:'年龄未记录'}}</text></view><text class="archived">✓ 已归档</text></view><view class="meta-grid"><view><text>病历号</text><text>{{notebook.header.caseNumber||registerId}}</text></view><view><text>就诊时间</text><text>{{formatTime(notebook.header.visitDate)}}</text></view><view><text>就诊科室</text><text>{{notebook.header.departmentName||'—'}}</text></view><view><text>接诊医生</text><text>{{notebook.header.physicianName||'—'}}</text></view></view></view><view class="section-card"><view class="section-head"><text class="number">01</text><view><text>病历摘要</text><text>MEDICAL SUMMARY</text></view></view><view class="field-list"><view><text>主诉</text><text>{{text(notebook.medicalSummary.readme)}}</text></view><view><text>现病史</text><text>{{text(notebook.medicalSummary.present)}}</text></view><view><text>既往史</text><text>{{text(notebook.medicalSummary.history)}}</text></view><view><text>过敏史</text><text>{{text(notebook.medicalSummary.allergy,'未记录明确过敏史')}}</text></view><view><text>体格检查</text><text>{{text(notebook.medicalSummary.physique)}}</text></view></view></view><view class="section-card diagnosis-card"><view class="section-head"><text class="number green">02</text><view><text>诊断信息</text><text>DIAGNOSIS</text></view></view><view class="primary-diagnosis"><text>初步诊断</text><text>{{text(notebook.preliminaryDiagnosis,'暂无初步诊断')}}</text></view><view class="diagnosis-grid"><view><text>确诊结论</text><text>{{text(notebook.diagnosis?.diagnosis,'暂无确诊')}}</text></view><view><text>疾病</text><text>{{diseases}}</text></view><view><text>治疗方案</text><text>{{text(notebook.diagnosis?.cure)}}</text></view><view><text>注意事项</text><text>{{text(notebook.diagnosis?.careful)}}</text></view></view></view><view id="exam-section" class="section-card"><view class="section-head"><text class="number purple">03</text><view><text>检查检验</text><text>EXAMINATION & LAB</text></view><text class="count">{{notebook.examItems?.length||0}} 项</text></view><view v-if="notebook.examItems?.length" class="exam-list"><view v-for="item in notebook.examItems" :key="item.id" class="exam-item"><view class="exam-top"><view class="exam-icon" :class="item.category">◇</view><view><text>{{item.techName||'检查项目'}}</text><text>{{item.category==='inspection'?'检验项目':'检查项目'}} · {{item.state||'状态未知'}}</text></view><text>{{formatTime(item.completedAt)}}</text></view><view class="result"><text>结果摘要</text><text>{{text(item.resultSummary,'暂无结果摘要')}}</text></view><view v-if="item.aiAnalysis" class="ai-analysis"><text>AI</text><text>{{item.aiAnalysis}}</text></view></view></view><view v-else class="empty">本次就诊暂无检查检验项目</view></view><view class="section-card"><view class="section-head"><text class="number orange">04</text><view><text>综合分析</text><text>CLINICAL ANALYSIS</text></view></view><view class="analysis">{{text(notebook.w3Analysis?.overallAnalysis,notebook.w3Analysis?.completed?'暂无综合分析内容':'待医生解读')}}</view></view><view class="section-card"><view class="section-head"><text class="number cyan">05</text><view><text>本次处方</text><text>PRESCRIPTION</text></view><text class="count">{{notebook.prescription?.items?.length||0}} 种</text></view><view v-if="notebook.prescription?.items?.length" class="drug-list"><view v-for="(item,index) in notebook.prescription.items" :key="index"><view class="drug-index">{{index+1}}</view><view><text>{{item.drugName||'药品'}}</text><text>{{item.drugUsage||'用法未记录'}}</text></view><text>× {{item.drugNumber||'—'}}</text></view></view><view v-else class="empty">本次就诊暂无处方</view></view><view class="disclaimer">◆ 本页为医生归档的门诊病历资料，仅供患者本人查阅，如有疑问请咨询接诊医生。</view></template></scroll-view></view></template>
